<template><div class="page-container"><PageHeader eyebrow="COLLECTION" title="我的收藏" description="创建收藏夹并管理喜欢的作品"><el-button type="primary" @click="folderDialog=true">新建收藏夹</el-button></PageHeader><div class="folder-layout"><aside class="folder-list"><button v-for="f in folders" :key="f.id" :class="{active:String(f.id)===String(activeId)}" @click="selectFolder(f)"><span>{{ f.folderName }}</span><small>{{ f.isPublic?'公开':'私密' }}</small></button></aside><section class="folder-content" v-loading="loading"><div class="folder-heading" v-if="activeFolder"><div><h2>{{ activeFolder.folderName }}</h2><p class="muted">{{ activeFolder.isPublic?'公开收藏夹':'仅自己可见' }}</p></div><el-button type="danger" text @click="removeFolder">删除收藏夹</el-button></div><div class="card-grid"><WorkCard v-for="w in works" :key="w.id" :work="w"/></div><EmptyState v-if="activeFolder&&!loading&&!works.length" description="这个收藏夹还没有作品"/><EmptyState v-if="!activeFolder" description="请先选择或新建收藏夹"/></section></div><el-dialog v-model="folderDialog" title="新建收藏夹" width="440"><el-form label-position="top"><el-form-item label="名称"><el-input v-model="folderForm.folderName"/></el-form-item><el-form-item label="可见性"><el-switch v-model="folderForm.isPublic" active-text="公开" inactive-text="私密"/></el-form-item></el-form><template #footer><el-button @click="folderDialog=false">取消</el-button><el-button type="primary" @click="createFolder">创建</el-button></template></el-dialog></div></template>
<script setup>import { computed,onMounted,reactive,ref } from 'vue';import { ElMessageBox } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import WorkCard from '../../components/WorkCard.vue';import EmptyState from '../../components/EmptyState.vue';import { favoriteApi } from '../../api/favorite';import { workApi } from '../../api/work';const folders=ref([]),activeId=ref(''),items=ref([]),works=ref([]),loading=ref(false),folderDialog=ref(false),folderForm=reactive({folderName:'',isPublic:false});const activeFolder=computed(()=>folders.value.find(f=>String(f.id)===String(activeId.value)));async function reload(){folders.value=await favoriteApi.folders();if(!activeId.value&&folders.value[0])await selectFolder(folders.value[0])}async function selectFolder(f){activeId.value=f.id;loading.value=true;items.value=await favoriteApi.items(f.id);const rs=await Promise.allSettled(items.value.map(i=>workApi.get(i.workId)));works.value=rs.filter(r=>r.status==='fulfilled').map(r=>r.value);loading.value=false}async function createFolder(){const f=await favoriteApi.createFolder(folderForm);folders.value.push(f);folderDialog.value=false;folderForm.folderName='';folderForm.isPublic=false;selectFolder(f)}async function removeFolder(){await ElMessageBox.confirm('删除收藏夹后其中的收藏项也会被删除，是否继续？');await favoriteApi.removeFolder(activeId.value);activeId.value='';works.value=[];reload()}onMounted(reload)</script>
